import 'dart:io'; void main() { final files = ['lib/features/home/presentation/screens/home_screen.dart','lib/features/history/presentation/screens/history_screen.dart','lib/features/profile/presentation/screens/profile_screen.dart','lib/features/analysis/presentation/screens/analysis_screen.dart']; for (var path in files) { final f = File(path); if (!f.existsSync()) continue; var c = f.readAsStringSync(); c = c.replaceAll(RegExp(r'\s*bottomNavigationBar:\s*Container\([^]+?_BottomNavItem[^]+?}\),[\r\n]{0,2}', multiLine: true), '\n'); c = c.replaceAll(RegExp(r'class _BottomNavItem extends StatelessWidget \{[^]+?}\s*}\s*', multiLine: true), '\n'); c = c.replaceAll(RegExp(r'\s*int _bottomNavIndex = [0-9];( //.*)?'), ''); f.writeAsStringSync(c); print('done '+path); } }
